      PROCEDURE T_CHANGELOG IS
/************************************************************************************************/
/* T_CHANGELOG.                                     									                          */
/*                                                                             									*/
/* This program unit is used to record the changes that have been made to this Report 					*/
/* after the initial release of the system.                                    									*/
/*                                                                             									*/
/* NOTE: It contains a single NULL statement because triggers must contain at  									*/
/* least one executable PL/SQL statement.                                      									*/
/*                                                                             									*/
/************************************************************************************************/
/* Date 		  	Developer     			Description of Change																				*/
/* ----------	-------------------		------------------------------------------------------------*/
/* 08/05/2015	Jenean Spencer, CCC		513033 : JV003																							*/ 
/*																	MVWF permit. 																								*/
/*                                                                             									*/
/* 10/19/2015	Jenean Spencer, CCC		513033 : JV003 : JVUAT-0040																	*/
/*																	Change P_ENVELOPE from JV_ENVELOPE_125 to JV_ENVELOPE_12.		*/  
/*                                                                             									*/
/* 01/16/2019	Jenean Spencer, CCC		417013 : JV2019.1.0	: Add WUTM CHIEF signature.							*/ 
/*																	Add Q_SIGNATURE query.  Add G_SIGNATURE to 									*/
/*																	M_WUTMB_SIGNATURE. 																					*/
/************************************************************************************************/
BEGIN

	NULL ;

END;

FUNCTION CF_WUTMB_Chief_F RETURN VARCHAR2 IS
CURSOR curAddress IS SELECT Pkg_WUTM_Util.F_Format_Address( AH.ADRH_Strt_1, AH.ADRH_Strt_2, AH.ADRH_City, AH.ADRH_St, AH.ADRH_Zip_Cd, AH.ADRH_Zip_Plus_Four, NULL, --pvCounty 'WASTE MANAGEMENT BUREAU') || CHR(10) || Pkg_WUTM_Util.F_To_Phone(AH.ADRH_Pri_Phn_No) Address FROM Organization O, Address_History AH, Address_History_Program_XRef AHPX WHERE O.Org_Id = AH.Org_Id AND AH.Org_Id = AHPX.Org_Id AND AH.AdTyp_Cd = AHPX.AdTyp_Cd AND AH.ADRH_No = AHPX.ADRH_No AND AHPX.Prog_Id = Pkg_Val.F_Val('K_Prog_Id_JV') AND AH.AdTyp_Cd = 'M' AND O.Busn_Nm = 'MT DEQ JV' ;
vChief VARCHAR2(100) ; BEGIN
vChief := Pkg_WUTM_Util.F_System_Parm_Char('WUTMB_CHIEF') || ', BUREAU CHIEF' ;
OPEN curAddress ; FETCH curAddress INTO :CP_JV_Addr ; CLOSE curAddress ;
RETURN(vChief) ; EXCEPTION WHEN OTHERS THEN IF curAddress%ISOPEN THEN CLOSE curAddress ; END IF ; END ;

FUNCTION CF_Permittees_F RETURN VARCHAR2 IS BEGIN
IF :CS_Org_Count = 1 THEN :CP_Operate_U := 'IS LICENSED TO OPERATE' ; --uppercase :CP_Operate_L := LOWER(:CP_Operate_U) ; --lowercase RETURN(:CS_Permittee_First) ; ELSE :CP_Operate_U := 'ARE LICENSED TO OPERATE' ; --uppercase :CP_Operate_L := LOWER(:CP_Operate_U) ; --lowercase RETURN(Pkg_WUTM_Util.F_Get_Permittees( piPerm_Num => :Perm_Num, piProg_Id => :Prog_Id, pdEffective_Dt => :Perm_Exp_Date, pvFormat => 'FIRST_LAST', pvDelimiter => ', ')) ; END IF ;
END ;

FUNCTION CF_File_F RETURN VARCHAR2 IS vSep VARCHAR2(1) ; --Directory seperator. BEGIN
--UNIX/LINUX IF INSTR(:P_AS_Path, '/') > 0 THEN vSep := '/' ;
--WINDOWS ELSE vSep := '\' ; END IF ;
IF :P_AS_Path IS NOT NULL THEN RETURN( RTRIM(:P_AS_Path, vSep) || vSep || REPLACE(:Permit, '-', '') || '_' || :P_Distr_Abbr || '_' || TO_CHAR(:Renewal_Year)) ; ELSE RETURN(NULL) ; END IF ; EXCEPTION WHEN OTHERS THEN RAISE ; END ;

FUNCTION CF_MVWF_Permit_F RETURN VARCHAR2 IS cbDEBUG CONSTANT BOOLEAN := FALSE ;
vExists VARCHAR2(1000) ; BEGIN
:CP_JV_Envelope := Pkg_WUTM_Util.F_Get_Rep_Description( pvRep_Name => :P_Envelope, piProg_Id => Pkg_Val.F_Val('K_Prog_Id_JV')) ;
CASE UPPER(TRIM(:P_Sort)) WHEN 'COUNTY' THEN :CP_Sort_Descr := 'County, Site' ; WHEN 'PERMITTEE' THEN :CP_Sort_Descr := 'Permittee, Permit' ; ELSE :CP_Sort_Descr := INITCAP(:P_Sort) ; END CASE ;
:CP_Permit_Dtl := 'Renewal Year = ''' || :P_Renewal_Year || '''' ;
--Setup the hyperlink for generate report to include a --an envelope for each letter. --Hyperlink can only be setup if P_ENVELOPE & P_REPORT_SERVER are defined. IF :P_Envelope IS NOT NULL AND :P_Report_Server IS NOT NULL THEN vExists := 'EXISTS(' || 'SELECT * ' || 'FROM ' || 'Permit_Type PT, ' || 'Permit P, ' || 'Status_Type ST, ' || 'Application A, ' || 'Site_Affiliation SA2, ' || 'Site_Affil_Type SAT, ' || 'Site S2 ' || 'WHERE ' || 'PT.Perm_Type_Id = P.Perm_Type_Id ' || 'AND P.Stat_Type_Id = ST.Stat_Type_Id ' || 'AND P.Perm_Num = A.Perm_Num ' || 'AND A.Site_Affil_Id = SA2.Site_Affil_Id ' || 'AND SA2.Site_Id = S2.Site_Id ' || 'AND SA2.Site_Affil_Type_Id = SAT.Site_Affil_Type_Id ' || 'AND PT.Perm_Type_Name = ''MVWF'' ' --Motor Vehicle Wrecking Facility - Renewal*/ || 'AND SAT.Site_Affil_Type_Name = ''PERM'' ' --Permitee || 'AND ST.Stat_Type_Name = ''JVA'' ' --Active || 'AND A.Prog_Id = ' || Pkg_Val.F_Val('K_Prog_Id_JV') || :P_Criteria_Envelope || ' ' || 'AND SA2.Site_Affil_Id = SA.Site_Affil_Id) ' ;
:CP_URL_All_Envelope := TRIM(:P_Report_Server) || '?DEQ' || '&destype=cache' || '&desformat=PDF' || '&report=' || :P_Envelope ;
IF :P_Permittee IS NOT NULL THEN :CP_URL_All_Envelope := :CP_URL_All_Envelope || '&P_ORG_NAME=' || Utl_URL.Escape( URL => :P_Permittee, Escape_Reserved_Chars => TRUE) ; END IF ;
:CP_URL_All_Envelope := :CP_URL_All_Envelope || '&P_EXISTS=' || vExists ;
IF cbDEBUG THEN SRW.Message( Msg_Number => 20000, Msg_Text_String => 'LENGTH(:CP_URL_All_Envelope) = ' || LENGTH(:CP_URL_All_Envelope)) ; END IF ;
ELSE RETURN(NULL) ; END IF ;
RETURN(Pkg_WUTM_Util.F_Get_Rep_Description( pvRep_Name => 'MVWF_PERMIT', piProg_Id => Pkg_Val.F_Val('K_Prog_Id_JV')) || '(s)') ;
END ;

FUNCTION CF_URL_Envelope_F RETURN VARCHAR2 IS
BEGIN
--Setup the hyperlink for R_G_ORG.F_PERMITTEE_ADDR --Hyperlink can only be setup if P_ENVELOPE & P_REPORT_SERVER are defined. IF :P_Envelope IS NOT NULL AND :P_Report_Server IS NOT NULL THEN
RETURN(TRIM(:P_Report_Server) || '?DEQ' || '&destype=cache' || '&desformat=PDF' || '&report=' || :P_Envelope || '&P_ORG_ID=' || :Org_Id || '&P_SITE_ID=' || :SA_Site_Id) ;
ELSE RETURN(NULL) ; END IF ;
END ;

      FUNCTION F_CP_URL_ALL_Envelope_FT 
RETURN BOOLEAN IS 
	cbDEBUG			CONSTANT BOOLEAN := FALSE ; 
BEGIN 
	IF cbDEBUG THEN 
  	RETURN(TRUE) ; 
	ELSE
		RETURN(FALSE) ; 
	END IF ;   
END ;

      FUNCTION After_Param_Form 
RETURN BOOLEAN IS 

	cbDEBUG									CONSTANT	BOOLEAN				:= FALSE ; --TRUE ; 

  			  							 													 -- 1234567890123456789012345678901234567890123456789012345678890	
	cvPERM_NAME							CONSTANT 	VARCHAR2(20) 	:= 'UPPER(P.Perm_Name)' ;
	cvPERM_NUM							CONSTANT 	VARCHAR2(20) 	:= 'P.Perm_Num' ;
	cvPERMITTEE							CONSTANT 	VARCHAR2(100) := 'Pkg_WUTM_Util.F_Format_Org_Name('
																						            || 'O2.Busn_Nm, '
																						            || 'O2.Frst_Nm, '
																						            || 'O2.MI, '
																						            || 'O2.Lst_Nm, '
																						            || '''LAST_FIRST'')' ; 
	cvRENEWAL_YEAR					CONSTANT 	VARCHAR2(40) 	:= 'TO_CHAR(P.Perm_Eff_Date, ''YYYY'')' ; 
	cvSITE_NAME							CONSTANT 	VARCHAR2(20) 	:= 'UPPER(S.Site_Name)' ;
	cvSTATUS_DT							CONSTANT	VARCHAR2(20) 	:= 'TRUNC(P.Status_Date)' ; 

	vCriteria								VARCHAR2(200) ; 	

	CURSOR
		curYear
	IS
		SELECT 
			TO_CHAR(P.Perm_Eff_Date, 'YYYY') Renewal_Year
		FROM
			Permit P
		WHERE
			P.Perm_Num = :P_Perm_Num ; 

	FUNCTION F_Criteria_Number_Bind(
		pvColumn_1				IN	VARCHAR2, 		
		pvBind_Variable		IN	VARCHAR2)
	RETURN VARCHAR2 IS 
		nValue				NUMBER ;

		vCriteria 		VARCHAR2(1000) ; 		
		vLabel				VARCHAR2(30) ; 		
		vValue				VARCHAR2(200) ; 
	BEGIN 

		nValue := SRW.Get_Value(pvBind_Variable) ; 

	  IF nValue IS NOT NULL THEN 

			vCriteria := ' AND '
										|| pvColumn_1
										|| ' = :' 
											|| pvBind_Variable ; 

	  END IF ; 

		IF nValue IS NOT NULL THEN 

			CASE UPPER(TRIM(pvBind_Variable))
			WHEN 'P_PERM_NUM' THEN 
				vLabel := 'Permit' ; 		
				vValue := Pkg_WUTM_Util.F_Get_Perm_Name(
										piPerm_Num => nValue) ; 

				IF vValue IS NULL THEN 
					vValue := nValue ; 	
				ELSE
					vValue := Pkg_WUTM_Util.F_Add_Delimiter(
											pvDelimiter => '''', 
											pvText => vValue) 
											|| ' (' 
											|| nValue
											|| ')' ; 
				END IF ; 

				ELSE

		  	vLabel := pvBind_Variable ; 
		  END CASE ; 

			:P_Subtitle := :P_Subtitle
											|| CHR(10) 
											|| vLabel											
											|| ' = ' 											
											|| vValue ; 
		END IF ; 

		RETURN(vCriteria) ; 	
	END F_Criteria_Number_Bind ; 		

	FUNCTION F_Criteria_Number_Value(
		pvColumn_1				IN	VARCHAR2, 		
		pvBind_Variable		IN	VARCHAR2)
	RETURN VARCHAR2 IS 
		nValue				NUMBER ; 

		vCriteria 		VARCHAR2(1000) ; 				

	BEGIN 

		nValue := SRW.Get_Value(pvBind_Variable) ; 

	  IF nValue IS NOT NULL THEN 	      	   
			vCriteria := ' AND '
										|| pvColumn_1
										|| ' = ' 
										|| nValue ; 
	  END IF ; 

		RETURN(vCriteria) ; 	
	END F_Criteria_Number_Value ; 		

	FUNCTION F_Criteria_Varchar2_Bind(
		pvColumn_1				IN	VARCHAR2, 		
		pvBind_Variable		IN	VARCHAR2)
	RETURN VARCHAR2 IS 
		vCriteria 		VARCHAR2(1000) ; 		
		vLabel				VARCHAR2(30) ; 
		vOperator			VARCHAR2(10) ; 		
		vValue				VARCHAR2(200) ; 
	BEGIN 

		vValue := SRW.Get_Value(pvBind_Variable) ; 

	  IF INSTR(vValue, '%') > 0
	  OR INSTR(vValue, '_') > 0 THEN 

			vCriteria := ' AND '
										|| pvColumn_1
										|| ' LIKE UPPER(TRIM(:' 
											|| pvBind_Variable
											|| '))' ; 

			vOperator := ' like ' ; 

	  ELSIF vValue IS NOT NULL THEN   			
			vCriteria := ' AND '
										|| pvColumn_1
										|| ' = UPPER(TRIM(:' 
											|| pvBind_Variable
											|| '))' ; 			  															

			vOperator := ' = ' ; 
	  END IF ; 

		IF vValue IS NOT NULL THEN 
			CASE UPPER(TRIM(pvBind_Variable))
			WHEN 'P_PERM_NAME' THEN 
				vLabel := 'Permit' ; 	
			WHEN 'P_PERMITTEE' THEN 
				vLabel := 'Permittee' ; 					
			WHEN 'P_RENEWAL_YEAR' THEN 
				vLabel := 'Renewal Year' ; 
			WHEN 'P_SITE_NAME' THEN 
				vLabel := 'Site' ;
		  ELSE
		  	vLabel := pvBind_Variable ; 
		  END CASE ; 

			:P_Subtitle := :P_Subtitle
											|| CHR(10) 
											|| vLabel											
											|| vOperator
											|| ''''
											|| UPPER(TRIM(vValue))
											|| '''' ; 
		END IF ; 

		RETURN(vCriteria) ; 	
	END F_Criteria_Varchar2_Bind ; 		

	FUNCTION F_Criteria_Varchar2_Value(
		pvColumn_1				IN	VARCHAR2, 		
		pvBind_Variable		IN	VARCHAR2)
	RETURN VARCHAR2 IS 
		vCriteria 		VARCHAR2(1000) ; 			
		vOperator			VARCHAR2(5) ; 		
		vValue				VARCHAR2(200) ; 
	BEGIN 

		vValue := UPPER(TRIM(SRW.Get_Value(pvBind_Variable))) ; 

	  IF INSTR(vValue, '%') > 0
	  OR INSTR(vValue, '_') > 0 THEN 

			vCriteria := ' AND '
										|| pvColumn_1
										|| ' LIKE ''' 
										|| Utl_URL.Escape(
												URL => vValue, 
												Escape_Reserved_Chars => TRUE) 
										|| '''' ; 

			vOperator := ' AND ' ; 

	  ELSIF vValue IS NOT NULL THEN   			
			vCriteria := ' AND '
										|| pvColumn_1
										|| ' = ''' 
										|| Utl_URL.Escape(
												URL => vValue, 
												Escape_Reserved_Chars => TRUE) 
										|| '''' ; 			  															

			vOperator := ' = ' ; 
	  END IF ; 

		RETURN(vCriteria) ; 	
	END F_Criteria_Varchar2_Value ; 		

BEGIN 

	--P_Renewal_Year
	IF :P_Renewal_Year IS NULL THEN 

		IF :P_Perm_Num IS NOT NULL THEN 

			OPEN curYear ; 
			FETCH curYear INTO :P_Renewal_Year ; 
			CLOSE curYear ; 

		END IF ; 

		:P_Renewal_Year := NVL(:P_Renewal_Year, TO_CHAR(ROUND(SYSDATE, 'YYYY'), 'YYYY')) ; 

	END IF ; 

	IF TRIM(:P_Sort) IS NULL THEN 
		:P_Sort := 'PERMIT' ; 
	END IF ; 

	:P_Criteria_Permit := :P_Criteria_Permit
													|| F_Criteria_Varchar2_Bind(
															pvColumn_1 => cvRENEWAL_YEAR, 														
															pvBind_Variable => 'P_Renewal_Year') ; 

	:P_Criteria_Envelope := :P_Criteria_Envelope
													|| F_Criteria_Varchar2_Value(
															pvColumn_1 => cvRENEWAL_YEAR, 														
															pvBind_Variable => 'P_Renewal_Year') ; 

	--P_Perm_Name
	:P_Criteria_Permit := :P_Criteria_Permit
													|| F_Criteria_Varchar2_Bind(
															pvColumn_1 => cvPERM_NAME, 														
															pvBind_Variable => 'P_Perm_Name') ; 

	:P_Criteria_Envelope := :P_Criteria_Envelope
													|| F_Criteria_Varchar2_Value(
															pvColumn_1 => cvPERM_NAME, 														
															pvBind_Variable => 'P_Perm_Name') ; 

	--P_Site_Name
	:P_Criteria_Permit := :P_Criteria_Permit
													|| F_Criteria_Varchar2_Bind(
															pvColumn_1 => cvSITE_NAME, 														
															pvBind_Variable => 'P_Site_Name') ; 

	:P_Criteria_Envelope := :P_Criteria_Envelope
													|| F_Criteria_Varchar2_Value(
															pvColumn_1 => REPLACE(cvSITE_NAME, 'S.', 'S2.'),  														
															pvBind_Variable => 'P_Site_Name') ; 

	--P_Status_Dt_Begin & P_Status_Dt_End 
	IF :P_Status_Dt_Begin IS NOT NULL 
	AND :P_Status_Dt_End IS NOT NULL THEN 		

		:P_Criteria_Permit := :P_Criteria_Permit
														|| ' AND (' 
														|| cvSTATUS_DT
														|| ' >= :P_Status_Dt_Begin'
														|| ' AND ' 
														|| cvSTATUS_DT
														|| ' <= :P_Status_Dt_End'
														|| ')' ; 

		:P_Criteria_Envelope := :P_Criteria_Envelope
														|| ' AND (' 
														|| cvSTATUS_DT
														|| ' >= TO_DATE(''' || TO_CHAR(:P_Status_Dt_Begin, 'MM/DD/YYYY') || ''', ''MM/DD/YYYY'') '
														|| ' AND ' 
														|| cvSTATUS_DT
														|| ' <= TO_DATE(''' || TO_CHAR(:P_Status_Dt_End, 'MM/DD/YYYY') || ''', ''MM/DD/YYYY'') '
														|| ')' ; 

		:P_Subtitle := :P_Subtitle
										|| CHR(10) 
										|| 'Permit Status Date between '
										|| TO_CHAR(:P_Status_Dt_Begin, 'MM/DD/YYYY') 
										|| ' and '
										|| TO_CHAR(:P_Status_Dt_End, 'MM/DD/YYYY') ; 

	ELSIF :P_Status_Dt_Begin IS NOT NULL THEN	

		:P_Criteria_Permit := :P_Criteria_Permit
													|| ' AND ' 
													|| cvSTATUS_DT
													|| ' = :P_Status_Dt_Begin' ; 

		:P_Criteria_Envelope := :P_Criteria_Envelope
														|| ' AND ' 
														|| cvSTATUS_DT
														|| ' = TO_DATE(''' || TO_CHAR(:P_Status_Dt_Begin, 'MM/DD/YYYY') || ''', ''MM/DD/YYYY'') ' ;

		:P_Subtitle := :P_Subtitle
										|| CHR(10) 
										|| 'Permit Status Date =  '
										|| TO_CHAR(:P_Status_Dt_Begin, 'MM/DD/YYYY')  ; 

	ELSIF :P_Status_Dt_End IS NOT NULL THEN

		:P_Criteria_Permit := :P_Criteria_Permit
													|| ' AND ' 
													|| cvSTATUS_DT
													|| ' = :P_Status_Dt_End' ; 

		:P_Criteria_Envelope := :P_Criteria_Envelope
														|| ' AND ' 
														|| cvSTATUS_DT
														|| ' = TO_DATE(''' || TO_CHAR(:P_Status_Dt_End, 'MM/DD/YYYY') || ''', ''MM/DD/YYYY'') ' ;

		:P_Subtitle := :P_Subtitle
										|| CHR(10) 
										|| 'Permit Status Date = '
										|| TO_CHAR(:P_Status_Dt_End, 'MM/DD/YYYY') ; 

	END IF ; 

	--P_Permittee
	vCriteria := F_Criteria_Varchar2_Bind(
								pvColumn_1 => cvPERMITTEE, 														
								pvBind_Variable => 'P_Permittee') ; 

	IF vCriteria IS NOT NULL THEN 
		:P_Criteria_Permit := :P_Criteria_Permit
														|| ' AND EXISTS('
																	|| 'SELECT * '
																	|| 'FROM '
																		|| 'Site_Affil_Type SAT2, '
																		|| 'Site_Affiliation SA2, '
																		|| 'Organization O2 '
																	|| 'WHERE '
																		|| 'SAT2.Site_Affil_Type_Id = SA2.Site_Affil_Type_Id '
																		|| 'AND SA2.Org_Id = O2.Org_Id '
																		|| 'AND SAT2.Site_Affil_Type_Name = ''PERM'' '
																		|| 'AND SA2.Site_Id = S.Site_Id '
																		|| 'AND NVL(TRUNC(SA2.Site_Affil_Start_Date), NVL(P.Perm_Exp_Date, TRUNC(SYSDATE))) <= NVL(P.Perm_Exp_Date, TRUNC(SYSDATE)) ' 
																		|| 'AND NVL(TRUNC(SA2.Site_Affil_End_Date), NVL(P.Perm_Exp_Date, TRUNC(SYSDATE))) >= NVL(P.Perm_Exp_Date, TRUNC(SYSDATE)) ' 
																		|| vCriteria
																		|| ') ' ;
	END IF ; 

	:P_Subtitle := LTRIM(:P_Subtitle, CHR(10)) ; 

	--P_Perm_Num
	:P_Criteria_Permit := :P_Criteria_Permit
													|| F_Criteria_Number_Bind(
															pvColumn_1 => cvPERM_NUM,
															pvBind_Variable => 'P_Perm_Num') ; 

	:P_Criteria_Envelope := :P_Criteria_Envelope
													|| F_Criteria_Number_Value(
															pvColumn_1 => cvPERM_NUM,
															pvBind_Variable => 'P_Perm_Num') ; 

	--Setup P_REPORT_SERVER for permittee envelope. 
	--FYI:  If P_ENVELOPE is not defined then P_REPORT_SERVER is NOT required. 
	--
	IF :P_Envelope IS NOT NULL 
	AND :P_Report_Server IS NULL THEN --Standard usage is to look up the REPORT SERVER. 		
		:P_Report_Server := Pkg_WUTM_Util.F_Get_Rep_URL(
													pvRep_Name => :P_Envelope,
													piProg_Id => Pkg_Val.F_Val('K_Prog_Id_JV')) ;																
	END IF ; 

	IF :P_AS_Path IS NOT NULL 
	AND :P_Distr_Abbr IS NULL THEN 
		:P_Distr_Abbr := Pkg_WUTM_Util.F_Get_Rep_Distr_Abbr(
											pvRep_Name => 'MVWF_PERMIT',
											piProg_Id => Pkg_Val.F_Val('K_Prog_Id_JV')) ;																
	END IF ; 

	IF cbDEBUG THEN 
		SRW.Message(
			Msg_Number => 20000,
			Msg_Text_String => 'After_Param_Form : P_CRITERIA_PERMIT = '
													|| NVL(:P_Criteria_Permit, '[NULL]')) ; 

		SRW.Message(
			Msg_Number => 20000,
			Msg_Text_String => 'After_Param_Form : P_CRITERIA_ENVELOPE = '
													|| NVL(:P_Criteria_Envelope, '[NULL]')) ; 

		SRW.Message(
			Msg_Number => 20000,
			Msg_Text_String => 'After_Param_Form : P_REPORT_SERVER = '
													|| NVL(:P_Report_Server, '[NULL]')) ; 
	END IF ; 

  RETURN(TRUE) ; 
EXCEPTION
WHEN OTHERS THEN 

	IF curYear%ISOPEN THEN
		CLOSE curYear ; 	
	END IF ; 

	RAISE ; 		
END ;

      FUNCTION B_Error_Permittee_FT 
RETURN BOOLEAN IS 
BEGIN 
	IF :CS_Permittee_First IS NULL THEN 
		RETURN(TRUE) ; 
	ELSE
		RETURN(FALSE) ; 
	END IF ; 

END ;
